    height: "100%"
  },
  swipeIndicator: {
    position: 'absolute',
    top: 20,
    padding: 10,
    borderRadius: 25,
    backgroundColor: 'rgba(0,0,0,0.5)',
    zIndex: 10
  },
  likeIndicator: {
    right: 20,
    backgroundColor: 'rgba(76, 175, 80, 0.8)'
  },
  nopeIndicator: {
    left: 20,
    backgroundColor: 'rgba(255, 107, 107, 0.8)'
  },
